let state=safeLoad(), current=[], idx=0, score=0;
function safeLoad(){try{const s=JSON.parse(localStorage.getItem('schoolv4')||'{}');return {answers:s.answers||{},exams:Array.isArray(s.exams)?s.exams:[]};}catch(e){return {answers:{},exams:[]};}}
function save(){localStorage.setItem('schoolv4',JSON.stringify(state));}
function el(id){return document.getElementById(id);}function txt(t){return document.createTextNode(String(t));}
function clear(node){while(node.firstChild)node.removeChild(node.firstChild);}function page(id){document.querySelectorAll('.page').forEach(p=>p.classList.toggle('hidden',p.id!==id));document.querySelectorAll('#nav button').forEach(b=>b.classList.toggle('on',b.dataset.page===id));renderProgress();}
function button(label,fn,cls=''){const b=document.createElement('button');b.className=cls;b.textContent=label;b.addEventListener('click',fn);return b;}
function initNav(){const nav=el('nav');[['home','🏠 Inicio'],['exam','📝 Examen'],['ia','🤖 Tutor IA'],['data','💾 Progreso']].forEach(([p,l])=>{const b=button(l,()=>page(p));b.dataset.page=p;nav.appendChild(b);});}
function initHome(){const grid=el('subjects');clear(grid);Object.entries(SUBJECTS).forEach(([id,s])=>{const c=document.createElement('div');c.className='card subject';c.style.setProperty('--c',s[2]);const h=document.createElement('h3');h.textContent=s[1]+' '+s[0];const p=document.createElement('p');p.textContent='40 preguntas · rotación diaria';const b=button('Practicar',()=>startSubject(id),'btn');c.append(h,p,b);c.addEventListener('click',()=>startSubject(id));grid.appendChild(c);});}
function startSubject(s){current=QUESTIONS.filter(q=>q.s===s).slice(0,10);idx=0;score=0;el('quizTitle').textContent=SUBJECTS[s][1]+' '+SUBJECTS[s][0];page('quiz');renderQ();}
function renderQ(){const box=el('quizBox');clear(box);if(idx>=current.length){finishQuiz();return;}const q=current[idx];el('quizCounter').textContent='Pregunta '+(idx+1)+'/'+current.length;const h=document.createElement('h3');h.textContent=q.q;box.appendChild(h);q.o.forEach((o,i)=>{const opt=button(o,()=>answer(i),'qopt');box.appendChild(opt);});const ex=document.createElement('p');ex.id='explain';box.appendChild(ex);}
function answer(i){const q=current[idx];document.querySelectorAll('#quizBox .qopt').forEach((b,j)=>{b.disabled=true;if(j===q.c)b.classList.add('ok');if(j===i&&i!==q.c)b.classList.add('no');});if(i===q.c)score++;state.answers[q.id]=i===q.c;save();const ex=el('explain');clear(ex);ex.appendChild(txt((i===q.c?'✅ ':'❌ ')+q.e));ex.appendChild(document.createElement('br'));ex.appendChild(button('Siguiente',()=>{idx++;renderQ();},'btn'));}
function finishQuiz(){const box=el('quizBox');clear(box);const h=document.createElement('h2');h.textContent='Resultado '+score+'/'+current.length;box.appendChild(h);box.appendChild(button('Terminar',()=>page('home'),'btn'));}
function startExam(){current=QUESTIONS.slice().sort(()=>Math.random()-.5).slice(0,20);idx=0;score=0;renderExamQ();}
function renderExamQ(){const box=el('examBox');clear(box);if(idx>=current.length){const pct=Math.round(score/current.length*100);state.exams.push({date:new Date().toISOString(),score,pct});save();const h=document.createElement('h3');h.textContent=(pct>=50?'✅ Aprobado':'💪 Practica más');const p=document.createElement('p');p.textContent=score+'/'+current.length+' ('+pct+'%)';box.append(h,p);return;}const q=current[idx];const h=document.createElement('h3');h.textContent=q.q;box.appendChild(h);q.o.forEach((o,i)=>box.appendChild(button(o,()=>{if(i===q.c)score++;idx++;renderExamQ();},'qopt')));}
async function askOllama(prompt){if(window.electronAPI&&window.electronAPI.ollamaChat){const r=await window.electronAPI.ollamaChat(prompt);if(r&&r.success)return r.response;throw new Error((r&&r.error)||'IPC Ollama error');}const res=await fetch('http://localhost:11434/api/generate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'gemma2:2b',prompt,stream:false})});if(!res.ok)throw new Error('HTTP '+res.status);const d=await res.json();return d.response||'Sin respuesta';}
function addMsg(t,cls){const d=document.createElement('div');d.className='msg '+cls;d.textContent=t;el('chat').appendChild(d);el('chat').scrollTop=el('chat').scrollHeight;return d;}
async function sendChat(){const input=el('prompt');const msg=input.value.trim().slice(0,500);if(!msg)return;input.value='';addMsg(msg,'u');const pending=addMsg('Pensando...','b');try{const ans=await askOllama('Eres tutor educativo de 6º Primaria en España. Explica claro y con ejemplos. '+msg);pending.remove();addMsg(ans,'b');}catch(e){pending.remove();addMsg('❌ No se pudo conectar con Ollama. Ejecuta ollama serve y descarga gemma2:2b.','b');}}
function renderProgress(){const total=QUESTIONS.length, done=Object.keys(state.answers).length;const p=el('progress');clear(p);const t=document.createElement('p');t.textContent='Preguntas respondidas: '+done+'/'+total;const bar=document.createElement('div');bar.className='bar';const sp=document.createElement('span');sp.style.width=Math.round(done/total*100)+'%';bar.appendChild(sp);const e=document.createElement('p');e.textContent='Exámenes: '+state.exams.length;p.append(t,bar,e);}
function exportData(){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'}));a.download='school-v4-progreso.json';a.click();}
function importData(ev){const f=ev.target.files[0];if(!f)return;const r=new FileReader();r.onload=e=>{try{const s=JSON.parse(e.target.result);state={answers:s.answers||{},exams:Array.isArray(s.exams)?s.exams:[]};save();renderProgress();}catch{alert('JSON no válido');}};r.readAsText(f);}
document.addEventListener('DOMContentLoaded',()=>{initNav();initHome();el('backQuiz').addEventListener('click',()=>page('home'));el('backExam').addEventListener('click',()=>page('home'));el('backIa').addEventListener('click',()=>page('home'));el('backData').addEventListener('click',()=>page('home'));el('startExam').addEventListener('click',startExam);el('send').addEventListener('click',sendChat);el('prompt').addEventListener('keydown',e=>{if(e.key==='Enter')sendChat();});el('exportBtn').addEventListener('click',exportData);el('importInput').addEventListener('change',importData);addMsg('¡Hola! Pregúntame algo de 6º de Primaria.','b');if('serviceWorker' in navigator)navigator.serviceWorker.register('sw.js').catch(()=>{});page('home');});
